"use client";

import {
  useCallback,
  useEffect,
  useImperativeHandle,
  useRef,
} from "react";
import type {
  FilterStackHandle,
  FilterStackProps,
  FilterValue,
} from "./types";
import { isCategoryEmpty } from "./lib/default-is-empty";
import { validateCategorySchema } from "./lib/validate-schema";
import { useFilteredItems } from "./hooks/use-filtered-items";
import { useTextBuffer } from "./hooks/use-text-buffer";
import { FilterSection } from "./parts/filter-section";
import { FilterStackFooter } from "./parts/filter-stack-footer";
import { cn } from "@/lib/utils";

const SCHEMA_INSTABILITY_THRESHOLD = 5;

export function FilterStack<T = unknown>(props: FilterStackProps<T>) {
  const {
    items,
    categories,
    values,
    onChange,
    onFilteredChange,
    showClearAll = true,
    clearAllLabel = "Clear all",
    ariaLabel,
    className,
    ref,
  } = props;

  const valuesRef = useRef(values);
  const categoriesRef = useRef(categories);
  const onChangeRef = useRef(onChange);

  useEffect(() => {
    valuesRef.current = values;
    categoriesRef.current = categories;
    onChangeRef.current = onChange;
  });

  useEffect(() => {
    validateCategorySchema(
      categories as ReadonlyArray<import("./types").FilterCategory<unknown>>,
    );
  }, [categories]);

  const schemaInstabilityRef = useRef({
    last: categories,
    count: 0,
    warned: false,
  });
  useEffect(() => {
    const tracker = schemaInstabilityRef.current;
    if (tracker.last === categories) {
      tracker.count = 0;
      return;
    }
    tracker.last = categories;
    tracker.count++;
    if (
      tracker.count > SCHEMA_INSTABILITY_THRESHOLD &&
      !tracker.warned &&
      process.env.NODE_ENV !== "production"
    ) {
      tracker.warned = true;
      console.warn(
        "[filter-stack] `categories` prop is changing every render. " +
          "Wrap with `useMemo` or hoist to module scope to avoid re-computation.",
      );
    }
  }, [categories]);

  const commitText = useCallback((id: string, value: string) => {
    const current = valuesRef.current;
    onChangeRef.current({ ...current, [id]: value });
  }, []);

  const textBuffer = useTextBuffer(commitText);

  useFilteredItems(items, categories, values, onFilteredChange);

  const isEmpty = useCallback((): boolean => {
    for (const cat of categoriesRef.current) {
      if (!isCategoryEmpty(cat, valuesRef.current[cat.id])) return false;
    }
    return true;
  }, []);

  const clear = useCallback(
    (categoryId: string) => {
      const cat = categoriesRef.current.find((c) => c.id === categoryId);
      if (!cat) {
        if (process.env.NODE_ENV !== "production") {
          console.warn(
            `[filter-stack] clear("${categoryId}") — unknown category id; no-op.`,
          );
        }
        return;
      }
      if (cat.type === "text") textBuffer.cancel(categoryId);
      const next = { ...valuesRef.current };
      delete next[categoryId];
      if (cat.type === "checkbox-list" && cat.modeToggle) {
        delete next[`${categoryId}__mode`];
      }
      onChangeRef.current(next);
    },
    [textBuffer],
  );

  const clearAll = useCallback(() => {
    textBuffer.cancelAll();
    const current = valuesRef.current;
    const next: Record<string, FilterValue> = {};
    for (const key of Object.keys(current)) {
      if (key.endsWith("__mode")) next[key] = current[key];
    }
    onChangeRef.current(next);
  }, [textBuffer]);

  useImperativeHandle(
    ref,
    (): FilterStackHandle => ({ clearAll, clear, isEmpty }),
    [clearAll, clear, isEmpty],
  );

  let allEmpty = true;
  for (const cat of categories) {
    if (!isCategoryEmpty(cat, values[cat.id])) {
      allEmpty = false;
      break;
    }
  }

  return (
    <form
      noValidate
      role="region"
      aria-label={ariaLabel}
      className={cn("flex flex-col gap-3", className)}
      onSubmit={(e) => e.preventDefault()}
    >
      <div className="flex flex-col gap-3">
        {categories.map((cat) => (
          <FilterSection<T>
            key={cat.id}
            category={cat}
            values={values}
            onChange={onChange}
            items={items}
            textBuffer={textBuffer}
          />
        ))}
      </div>
      {showClearAll ? (
        <FilterStackFooter
          onClearAll={clearAll}
          disabled={allEmpty}
          label={clearAllLabel}
        />
      ) : null}
    </form>
  );
}

export { FilterStack } from "./filter-stack";
export { defaultIsEmpty } from "./lib/default-is-empty";
export type {
  CheckboxListFilter,
  CustomFilter,
  CustomFilterRenderProps,
  FilterCategory,
  FilterMode,
  FilterOption,
  FilterStackHandle,
  FilterStackProps,
  FilterValue,
  TextFilter,
  ToggleFilter,
} from "./types";
export { meta } from "./meta";

import type { ReactNode, Ref } from "react";

export type FilterValue = unknown;
export type FilterMode = "union" | "intersection";

export interface FilterOption {
  value: string;
  label: string;
}

interface BaseFilterCategory<T> {
  id: string;
  label: string;
  description?: string;
  predicate: (item: T, value: FilterValue) => boolean;
}

export interface CheckboxListFilter<T> extends BaseFilterCategory<T> {
  type: "checkbox-list";
  options: ReadonlyArray<FilterOption>;
  modeToggle?: boolean;
  defaultMode?: FilterMode;
  showSoloButtons?: boolean;
  isEmpty?: (value: FilterValue) => boolean;
}

export interface ToggleFilter<T> extends BaseFilterCategory<T> {
  type: "toggle";
  isEmpty: (value: FilterValue) => boolean;
}

export interface TextFilter<T> extends BaseFilterCategory<T> {
  type: "text";
  placeholder?: string;
  debounceMs?: number;
  isEmpty?: (value: FilterValue) => boolean;
}

export interface CustomFilterRenderProps<T> {
  value: unknown;
  onChange: (value: unknown) => void;
  items: ReadonlyArray<T>;
  fieldId: string;
}

export interface CustomFilter<T> extends BaseFilterCategory<T> {
  type: "custom";
  render: (props: CustomFilterRenderProps<T>) => ReactNode;
  isEmpty: (value: FilterValue) => boolean;
}

export type FilterCategory<T> =
  | CheckboxListFilter<T>
  | ToggleFilter<T>
  | TextFilter<T>
  | CustomFilter<T>;

export interface FilterStackProps<T = unknown> {
  items: ReadonlyArray<T>;
  categories: ReadonlyArray<FilterCategory<T>>;

  values: Record<string, FilterValue>;
  onChange: (values: Record<string, FilterValue>) => void;

  onFilteredChange?: (filtered: ReadonlyArray<T>) => void;

  showClearAll?: boolean;
  clearAllLabel?: string;

  ariaLabel?: string;
  className?: string;

  ref?: Ref<FilterStackHandle>;
}

export interface FilterStackHandle {
  clearAll(): void;
  clear(categoryId: string): void;
  isEmpty(): boolean;
}

"use client";

import { useEffect, useMemo, useRef } from "react";
import type { FilterCategory, FilterValue } from "../types";
import { applyFilters } from "../lib/apply-filters";

export function useFilteredItems<T>(
  items: ReadonlyArray<T>,
  categories: ReadonlyArray<FilterCategory<T>>,
  values: Record<string, FilterValue>,
  onFilteredChange?: (filtered: ReadonlyArray<T>) => void,
): ReadonlyArray<T> {
  const filtered = useMemo(
    () => applyFilters(items, categories, values),
    [items, categories, values],
  );

  const onFilteredChangeRef = useRef(onFilteredChange);
  useEffect(() => {
    onFilteredChangeRef.current = onFilteredChange;
  });

  useEffect(() => {
    const cb = onFilteredChangeRef.current;
    if (!cb) return;
    try {
      cb(filtered);
    } catch (err) {
      if (process.env.NODE_ENV !== "production") {
        console.error("[filter-stack] onFilteredChange threw:", err);
      }
    }
  }, [filtered]);

  return filtered;
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

export interface TextBufferApi {
  buffer: Record<string, string>;
  setBuffer: (id: string, value: string, debounceMs: number) => void;
  flush: (id: string) => void;
  cancel: (id: string) => void;
  flushAll: () => void;
  cancelAll: () => void;
}

type CommitText = (id: string, value: string) => void;

export function useTextBuffer(commitText: CommitText): TextBufferApi {
  const [buffer, setBufferState] = useState<Record<string, string>>({});
  const timersRef = useRef<Record<string, ReturnType<typeof setTimeout>>>({});
  const pendingRef = useRef<Record<string, string>>({});
  const commitTextRef = useRef(commitText);

  useEffect(() => {
    commitTextRef.current = commitText;
  });

  useEffect(() => {
    const timers = timersRef.current;
    return () => {
      for (const id of Object.keys(timers)) clearTimeout(timers[id]);
    };
  }, []);

  const clearBufferEntry = useCallback((id: string) => {
    setBufferState((prev) => {
      if (!(id in prev)) return prev;
      const next = { ...prev };
      delete next[id];
      return next;
    });
  }, []);

  const cancel = useCallback(
    (id: string) => {
      const timer = timersRef.current[id];
      if (timer) {
        clearTimeout(timer);
        delete timersRef.current[id];
      }
      delete pendingRef.current[id];
      clearBufferEntry(id);
    },
    [clearBufferEntry],
  );

  const flush = useCallback((id: string) => {
    const timer = timersRef.current[id];
    if (timer) {
      clearTimeout(timer);
      delete timersRef.current[id];
    }
    const value = pendingRef.current[id];
    if (value !== undefined) {
      delete pendingRef.current[id];
      commitTextRef.current(id, value);
    }
  }, []);

  const setBuffer = useCallback(
    (id: string, value: string, debounceMs: number) => {
      pendingRef.current[id] = value;
      setBufferState((prev) => ({ ...prev, [id]: value }));
      const existing = timersRef.current[id];
      if (existing) clearTimeout(existing);
      timersRef.current[id] = setTimeout(() => {
        delete timersRef.current[id];
        const pending = pendingRef.current[id];
        if (pending === undefined) return;
        delete pendingRef.current[id];
        commitTextRef.current(id, pending);
      }, debounceMs);
    },
    [],
  );

  const flushAll = useCallback(() => {
    for (const id of Object.keys(timersRef.current)) flush(id);
  }, [flush]);

  const cancelAll = useCallback(() => {
    for (const id of Object.keys(timersRef.current)) {
      clearTimeout(timersRef.current[id]);
      delete timersRef.current[id];
    }
    pendingRef.current = {};
    setBufferState({});
  }, []);

  return { buffer, setBuffer, flush, cancel, flushAll, cancelAll };
}

import type { FilterCategory, FilterValue } from "../types";
import { isCategoryEmpty } from "./default-is-empty";

export function applyFilters<T>(
  items: ReadonlyArray<T>,
  categories: ReadonlyArray<FilterCategory<T>>,
  values: Record<string, FilterValue>,
): ReadonlyArray<T> {
  const activePredicates: Array<(item: T) => boolean> = [];
  for (const cat of categories) {
    const value = values[cat.id];
    if (isCategoryEmpty(cat, value)) continue;
    activePredicates.push((item) => {
      try {
        return cat.predicate(item, value);
      } catch (err) {
        if (process.env.NODE_ENV !== "production") {
          console.error(
            `[filter-stack] predicate threw for category "${cat.id}":`,
            err,
          );
        }
        return false;
      }
    });
  }
  if (activePredicates.length === 0) return items;
  return items.filter((item) => activePredicates.every((p) => p(item)));
}

import type { FilterCategory, FilterValue } from "../types";

export function defaultCheckboxListIsEmpty(value: FilterValue): boolean {
  if (!Array.isArray(value)) return true;
  return value.length === 0;
}

export function defaultTextIsEmpty(value: FilterValue): boolean {
  if (typeof value !== "string") return true;
  return value.length === 0;
}

const TRUE = (): boolean => false;

export function isCategoryEmpty<T>(
  category: FilterCategory<T>,
  value: FilterValue,
): boolean {
  try {
    switch (category.type) {
      case "checkbox-list":
        return (category.isEmpty ?? defaultCheckboxListIsEmpty)(value);
      case "text":
        return (category.isEmpty ?? defaultTextIsEmpty)(value);
      case "toggle":
      case "custom":
        return category.isEmpty(value);
    }
  } catch (err) {
    if (process.env.NODE_ENV !== "production") {
      console.error(
        `[filter-stack] isEmpty threw for category "${category.id}":`,
        err,
      );
    }
    return TRUE();
  }
}

export const defaultIsEmpty = {
  checkboxList: defaultCheckboxListIsEmpty,
  text: defaultTextIsEmpty,
};

import type { FilterCategory } from "../types";

export const RESERVED_SUFFIXES = ["__mode"] as const;

export function validateCategorySchema(
  categories: ReadonlyArray<FilterCategory<unknown>>,
): void {
  if (process.env.NODE_ENV === "production") return;

  const seen = new Set<string>();
  for (const cat of categories) {
    for (const suffix of RESERVED_SUFFIXES) {
      if (cat.id.endsWith(suffix)) {
        console.error(
          `[filter-stack] category id "${cat.id}" ends in reserved suffix "${suffix}". ` +
            `Pick a different id; "${suffix}" is used internally for mode storage.`,
        );
      }
    }
    if (seen.has(cat.id)) {
      console.error(`[filter-stack] duplicate category id "${cat.id}".`);
    }
    seen.add(cat.id);
    if (
      cat.type === "checkbox-list" &&
      (!cat.options || cat.options.length === 0)
    ) {
      console.warn(
        `[filter-stack] checkbox-list category "${cat.id}" has no options.`,
      );
    }
    if (
      cat.type === "checkbox-list" &&
      cat.modeToggle === false &&
      cat.defaultMode !== undefined
    ) {
      console.warn(
        `[filter-stack] category "${cat.id}" has \`defaultMode\` but \`modeToggle\` is false; defaultMode will be ignored.`,
      );
    }
  }
}

"use client";

import { X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

interface ClearButtonProps {
  onClick: () => void;
  ariaLabel: string;
  variant?: "icon" | "text";
  label?: string;
  disabled?: boolean;
  className?: string;
}

export function ClearButton({
  onClick,
  ariaLabel,
  variant = "icon",
  label = "Clear all",
  disabled,
  className,
}: ClearButtonProps) {
  if (variant === "icon") {
    return (
      <Button
        type="button"
        variant="ghost"
        size="sm"
        onClick={onClick}
        disabled={disabled}
        aria-label={ariaLabel}
        className={cn(
          "size-7 p-0 text-muted-foreground hover:text-foreground",
          className,
        )}
      >
        <X aria-hidden="true" className="size-3.5" />
      </Button>
    );
  }
  return (
    <Button
      type="button"
      variant="outline"
      size="sm"
      onClick={onClick}
      disabled={disabled}
      aria-label={ariaLabel}
      aria-disabled={disabled || undefined}
      className={className}
    >
      <X aria-hidden="true" className="size-3" />
      {label}
    </Button>
  );
}

"use client";

import { Checkbox } from "@/components/ui/checkbox";
import type {
  CheckboxListFilter,
  FilterMode,
  FilterValue,
} from "../types";
import { SoloButton } from "./solo-button";

interface FilterCheckboxListProps<T> {
  category: CheckboxListFilter<T>;
  values: Record<string, FilterValue>;
  onChange: (values: Record<string, FilterValue>) => void;
  fieldId: string;
}

function asStringArray(value: FilterValue): string[] {
  if (!Array.isArray(value)) return [];
  return value.filter((v): v is string => typeof v === "string");
}

export function FilterCheckboxList<T>({
  category,
  values,
  onChange,
  fieldId,
}: FilterCheckboxListProps<T>) {
  const selected = asStringArray(values[category.id]);
  const selectedSet = new Set(selected);
  const showSolo = category.showSoloButtons === true;

  const handleToggle = (optionValue: string, checked: boolean) => {
    const next = checked
      ? [...selected, optionValue]
      : selected.filter((v) => v !== optionValue);
    onChange({ ...values, [category.id]: next });
  };

  const handleSolo = (optionValue: string) => {
    if (category.modeToggle) {
      const existing = values[`${category.id}__mode`];
      const fallbackMode: FilterMode = category.defaultMode ?? "union";
      const mode: FilterMode =
        existing === "union" || existing === "intersection"
          ? existing
          : fallbackMode;
      onChange({
        ...values,
        [category.id]: [optionValue],
        [`${category.id}__mode`]: mode,
      });
    } else {
      onChange({ ...values, [category.id]: [optionValue] });
    }
  };

  return (
    <ul
      role="group"
      aria-labelledby={fieldId}
      className="flex flex-col gap-1"
    >
      {category.options.map((opt) => {
        const optionId = `${fieldId}-opt-${opt.value}`;
        const checked = selectedSet.has(opt.value);
        return (
          <li
            key={opt.value}
            className="group flex items-center justify-between gap-2 rounded-md px-1 py-0.5 hover:bg-muted/40"
          >
            <label
              htmlFor={optionId}
              className="flex flex-1 cursor-pointer items-center gap-2 text-sm"
            >
              <Checkbox
                id={optionId}
                checked={checked}
                onCheckedChange={(state) => handleToggle(opt.value, state === true)}
              />
              <span className="truncate text-foreground">{opt.label}</span>
            </label>
            {showSolo ? (
              <span className="opacity-0 transition-opacity group-hover:opacity-100 focus-within:opacity-100">
                <SoloButton
                  optionLabel={opt.label}
                  onClick={() => handleSolo(opt.value)}
                />
              </span>
            ) : null}
          </li>
        );
      })}
    </ul>
  );
}

"use client";

import { Component, type ErrorInfo, type ReactNode } from "react";
import type { CustomFilter, FilterValue } from "../types";

interface FilterCustomProps<T> {
  category: CustomFilter<T>;
  values: Record<string, FilterValue>;
  onChange: (values: Record<string, FilterValue>) => void;
  items: ReadonlyArray<T>;
  fieldId: string;
}

class FilterErrorBoundary extends Component<
  { categoryId: string; children: ReactNode },
  { hasError: boolean }
> {
  state = { hasError: false };
  static getDerivedStateFromError() {
    return { hasError: true };
  }
  componentDidCatch(error: Error, info: ErrorInfo) {
    if (process.env.NODE_ENV !== "production") {
      console.error(
        `[filter-stack] custom render crashed for category "${this.props.categoryId}":`,
        error,
        info,
      );
    }
  }
  render() {
    if (this.state.hasError) {
      return (
        <p role="alert" className="text-xs text-destructive">
          Custom filter crashed — see console.
        </p>
      );
    }
    return this.props.children;
  }
}

export function FilterCustom<T>({
  category,
  values,
  onChange,
  items,
  fieldId,
}: FilterCustomProps<T>) {
  return (
    <FilterErrorBoundary categoryId={category.id}>
      {category.render({
        value: values[category.id],
        onChange: (next) => onChange({ ...values, [category.id]: next }),
        items,
        fieldId,
      })}
    </FilterErrorBoundary>
  );
}

"use client";

import { useId } from "react";
import type {
  FilterCategory,
  FilterMode,
  FilterValue,
} from "../types";
import { isCategoryEmpty } from "../lib/default-is-empty";
import { ClearButton } from "./clear-button";
import { ModeToggle } from "./mode-toggle";
import { FilterCheckboxList } from "./filter-checkbox-list";
import { FilterToggle } from "./filter-toggle";
import { FilterText } from "./filter-text";
import { FilterCustom } from "./filter-custom";
import type { TextBufferApi } from "../hooks/use-text-buffer";
import { defaultTextIsEmpty } from "../lib/default-is-empty";

interface FilterSectionProps<T> {
  category: FilterCategory<T>;
  values: Record<string, FilterValue>;
  onChange: (values: Record<string, FilterValue>) => void;
  items: ReadonlyArray<T>;
  textBuffer: TextBufferApi;
}

function readMode<T>(
  category: FilterCategory<T>,
  values: Record<string, FilterValue>,
): FilterMode {
  if (category.type !== "checkbox-list" || !category.modeToggle) return "union";
  const stored = values[`${category.id}__mode`];
  if (stored === "union" || stored === "intersection") return stored;
  return category.defaultMode ?? "union";
}

export function FilterSection<T>({
  category,
  values,
  onChange,
  items,
  textBuffer,
}: FilterSectionProps<T>) {
  const reactId = useId();
  const fieldId = `${reactId}-${category.id}`;
  const descriptionId = category.description ? `${fieldId}-desc` : undefined;
  const empty = isCategoryEmpty(category, values[category.id]);
  const showClear = !empty;

  const handleClear = () => {
    if (category.type === "text") textBuffer.cancel(category.id);
    const next = { ...values };
    delete next[category.id];
    if (category.type === "checkbox-list" && category.modeToggle) {
      delete next[`${category.id}__mode`];
    }
    onChange(next);
  };

  return (
    <fieldset className="flex flex-col gap-2 rounded-md border border-border bg-card/40 p-3">
      <div className="flex flex-wrap items-center justify-between gap-2">
        <legend
          id={fieldId}
          className="px-1 text-sm font-medium text-foreground"
        >
          {category.label}
        </legend>
        <div className="flex items-center gap-2">
          {category.type === "checkbox-list" && category.modeToggle ? (
            <ModeToggle
              value={readMode(category, values)}
              ariaLabel={`${category.label} mode`}
              onChange={(next) =>
                onChange({ ...values, [`${category.id}__mode`]: next })
              }
            />
          ) : null}
          {showClear ? (
            <ClearButton
              onClick={handleClear}
              ariaLabel={`Clear ${category.label}`}
            />
          ) : null}
        </div>
      </div>
      {category.description ? (
        <p id={descriptionId} className="px-1 text-xs text-muted-foreground">
          {category.description}
        </p>
      ) : null}
      {(() => {
        switch (category.type) {
          case "checkbox-list":
            return (
              <FilterCheckboxList
                category={category}
                values={values}
                onChange={onChange}
                fieldId={fieldId}
              />
            );
          case "toggle":
            return (
              <FilterToggle
                category={category}
                values={values}
                onChange={onChange}
                fieldId={fieldId}
              />
            );
          case "text": {
            const bufferValue = textBuffer.buffer[category.id];
            const debounceMs = category.debounceMs ?? 250;
            return (
              <FilterText
                category={category}
                values={values}
                onChange={onChange}
                fieldId={fieldId}
                descriptionId={descriptionId}
                bufferValue={bufferValue}
                onBufferChange={(v) =>
                  textBuffer.setBuffer(category.id, v, debounceMs)
                }
                onFlush={() => {
                  textBuffer.flush(category.id);
                  if (
                    bufferValue !== undefined &&
                    defaultTextIsEmpty(bufferValue) &&
                    typeof values[category.id] === "string" &&
                    !defaultTextIsEmpty(values[category.id])
                  ) {
                    onChange({ ...values, [category.id]: "" });
                  }
                }}
                onCancel={() => textBuffer.cancel(category.id)}
              />
            );
          }
          case "custom":
            return (
              <FilterCustom
                category={category}
                values={values}
                onChange={onChange}
                items={items}
                fieldId={fieldId}
              />
            );
        }
      })()}
    </fieldset>
  );
}

"use client";

import { ClearButton } from "./clear-button";

interface FilterStackFooterProps {
  onClearAll: () => void;
  disabled: boolean;
  label: string;
}

export function FilterStackFooter({
  onClearAll,
  disabled,
  label,
}: FilterStackFooterProps) {
  return (
    <div role="toolbar" className="flex justify-end pt-1">
      <ClearButton
        onClick={onClearAll}
        ariaLabel="Clear all filters"
        variant="text"
        label={label}
        disabled={disabled}
      />
    </div>
  );
}

"use client";

import { Input } from "@/components/ui/input";
import type { FilterValue, TextFilter } from "../types";

interface FilterTextProps<T> {
  category: TextFilter<T>;
  values: Record<string, FilterValue>;
  onChange: (values: Record<string, FilterValue>) => void;
  fieldId: string;
  bufferValue: string | undefined;
  onBufferChange: (value: string) => void;
  onFlush: () => void;
  onCancel: () => void;
  descriptionId?: string;
}

export function FilterText<T>({
  category,
  values,
  onChange,
  fieldId,
  bufferValue,
  onBufferChange,
  onFlush,
  onCancel,
  descriptionId,
}: FilterTextProps<T>) {
  const propValue =
    typeof values[category.id] === "string"
      ? (values[category.id] as string)
      : "";
  const inputValue = bufferValue !== undefined ? bufferValue : propValue;

  return (
    <Input
      id={fieldId}
      type="text"
      value={inputValue}
      placeholder={category.placeholder}
      aria-describedby={descriptionId}
      onChange={(e) => onBufferChange(e.target.value)}
      onBlur={onFlush}
      onKeyDown={(e) => {
        if (e.key === "Escape") {
          e.preventDefault();
          e.stopPropagation();
          onCancel();
          if (propValue.length > 0) {
            onChange({ ...values, [category.id]: "" });
          }
        }
      }}
    />
  );
}

"use client";

import { Switch } from "@/components/ui/switch";
import type { FilterValue, ToggleFilter } from "../types";

interface FilterToggleProps<T> {
  category: ToggleFilter<T>;
  values: Record<string, FilterValue>;
  onChange: (values: Record<string, FilterValue>) => void;
  fieldId: string;
}

export function FilterToggle<T>({
  category,
  values,
  onChange,
  fieldId,
}: FilterToggleProps<T>) {
  const checked = values[category.id] === true;
  return (
    <div className="flex items-center justify-between gap-2 px-1">
      <span id={`${fieldId}-state`} className="text-sm text-foreground">
        {checked ? "On" : "Off"}
      </span>
      <Switch
        id={fieldId}
        checked={checked}
        onCheckedChange={(next) =>
          onChange({ ...values, [category.id]: next })
        }
        aria-labelledby={fieldId}
      />
    </div>
  );
}

"use client";

import { ToggleGroup, ToggleGroupItem } from "@/components/ui/toggle-group";
import type { FilterMode } from "../types";

interface ModeToggleProps {
  value: FilterMode;
  onChange: (mode: FilterMode) => void;
  ariaLabel: string;
}

export function ModeToggle({ value, onChange, ariaLabel }: ModeToggleProps) {
  return (
    <ToggleGroup
      type="single"
      size="sm"
      value={value}
      onValueChange={(next) => {
        if (next === "union" || next === "intersection") onChange(next);
      }}
      aria-label={ariaLabel}
      variant="outline"
      className="text-xs"
    >
      <ToggleGroupItem value="union" className="px-2 text-xs">
        Union
      </ToggleGroupItem>
      <ToggleGroupItem value="intersection" className="px-2 text-xs">
        Intersection
      </ToggleGroupItem>
    </ToggleGroup>
  );
}

"use client";

import { Crosshair } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";

interface SoloButtonProps {
  optionLabel: string;
  onClick: () => void;
}

export function SoloButton({ optionLabel, onClick }: SoloButtonProps) {
  const ariaLabel = `Show only ${optionLabel}`;
  return (
    <TooltipProvider delayDuration={200}>
      <Tooltip>
        <TooltipTrigger asChild>
          <Button
            type="button"
            variant="ghost"
            size="sm"
            aria-label={ariaLabel}
            onClick={onClick}
            className="size-6 p-0 text-muted-foreground/70 hover:text-foreground"
          >
            <Crosshair aria-hidden="true" className="size-3.5" />
          </Button>
        </TooltipTrigger>
        <TooltipContent side="left">Solo: {optionLabel}</TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}
